const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const force = body.force === true;
let mode='power', reverifyDays=90;
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="reoon"',perPage:1},headers:pbH,json:true}); const v=(s.items&&s.items[0]&&s.items[0].value)||{}; if(v.mode)mode=v.mode; if(v.reverify_days!=null)reverifyDays=v.reverify_days; }catch(e){}
const cutoffMs = Date.now() - (reverifyDays*86400000);
let contacts=[];
if(Array.isArray(body.ids) && body.ids.length){
  for(const id of body.ids){ try{ const c=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records/'+id,headers:pbH,json:true}); contacts.push(c); }catch(e){} }
} else {
  const filter=body.filter||''; let page=1;
  while(true){ const qs=Object.assign({perPage:500,page,fields:'id,email,verified_at,verification_status,blocklisted'},filter?{filter}:{}); const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs,headers:pbH,json:true}); contacts=contacts.concat(r.items||[]); if(page>=(r.totalPages||1))break; page++; }
}
const out=[]; const seen=new Set();
const settled={verified:1,undeliverable:1,catch_all:1};
for(const c of contacts){
  if(!c.email||seen.has(c.email)) continue;
  if(c.blocklisted===true) continue;
  const vAt=c.verified_at? new Date(String(c.verified_at).replace(' ','T')).getTime():0;
  if(!force && vAt && vAt>cutoffMs && settled[c.verification_status]) continue;
  seen.add(c.email); out.push({json:{id:c.id,email:c.email,mode}});
}
// --- job_runs: open the run so the UI shows live progress ---
const sd=$getWorkflowStaticData('global'); const now=new Date().toISOString();
let jobId='';
try{ const j=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/job_runs/records',headers:pbH,body:{kind:'verify-reoon',label:'Verify emails (Reoon)',status:'running',total:out.length,processed:0,started:now},json:true}); jobId=j.id; }catch(e){}
sd.verifyJobId=jobId; sd.verifyProcessed=0; sd.verifyTotal=out.length;
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const batch=$('Loop').all();
const results=$input.all();
const now=new Date().toISOString();
function mapStatus(s){ s=(s||'').toString().toLowerCase();
  if(s==='safe'||s==='role_account') return 'verified';
  if(s==='catch_all') return 'catch_all';
  if(['invalid','disabled','disposable','spamtrap','inbox_full','undeliverable'].includes(s)) return 'undeliverable';
  return 'unknown'; }
const tasks=[];
for(let i=0;i<batch.length;i++){ const id=batch[i].json.id; const r=(results[i]&&results[i].json)||{}; tasks.push({id, vs:mapStatus(r.status)}); }
for(let i=0;i<tasks.length;i+=25){ await Promise.all(tasks.slice(i,i+25).map(t=>this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+t.id,headers:pbH,body:{verification_status:t.vs,verified_at:now},json:true}).catch(()=>{}))); }
// --- job_runs heartbeat ---
const sd=$getWorkflowStaticData('global');
if(sd.verifyJobId){ try{ sd.verifyProcessed=(sd.verifyProcessed||0)+batch.length; await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.verifyJobId,headers:pbH,body:{processed:sd.verifyProcessed,message:'verifying…'},json:true}); }catch(e){} }
return $input.all();

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const now=new Date().toISOString();
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="reoon"',perPage:1},headers:pbH,json:true}); const rec=s.items&&s.items[0]; if(rec){ const v=rec.value||{}; v.last_run=now; await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/settings/records/'+rec.id,headers:pbH,body:{value:v},json:true}); } }catch(e){}
// --- job_runs: close the run ---
const sd=$getWorkflowStaticData('global');
if(sd.verifyJobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.verifyJobId,headers:pbH,body:{status:'done',finished:now,processed:(sd.verifyProcessed||sd.verifyTotal||0),message:'Verification complete'},json:true}); }catch(e){} sd.verifyJobId=''; }
return [{json:{done:true,verified_at:now}}];
